import{_ as n,C as s,o as d,c as l,j as t,a,E as i,ag as r}from"./chunks/framework.DLWhSH9p.js";const b=JSON.parse('{"title":"Ideas","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ideas.md","filePath":"guide/ideas.md"}'),c={name:"guide/ideas.md"};function h(g,e,u,p,m,f){const o=s("SchemeImage");return d(),l("div",null,[e[0]||(e[0]=t("h1",{id:"ideas",tabindex:"-1"},[a("Ideas "),t("a",{class:"header-anchor",href:"#ideas","aria-label":'Permalink to "Ideas"'},"​")],-1)),e[1]||(e[1]=t("p",null,[a("The Ideas panel is where content starts. Generate ideas with AI, capture inspiration from YouTube, or add your own manually. It's the default view for a newly-selected channel — click "),t("strong",null,"Ideas"),a(" on the top-chrome stage rail to reach it from anywhere.")],-1)),i(o,{name:"ideas-panel",alt:"Ideas panel — three-column layout"}),e[2]||(e[2]=r('<h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The panel is a three-column layout:</p><ul><li><strong>Left — filter rail.</strong> Type (All / Shorts / Long-form), Source (All / AI / Discover / Manual — each with a live count and a coloured dot), Tags (pills that toggle in/out), and a Sort dropdown. Converted ideas are always hidden — once an idea becomes a script it lives on the Board instead.</li><li><strong>Centre — dense list.</strong> Each idea is a single row: checkbox · type badge · title + hook · source + source metadata · age · action arrow. Click any row to focus it in the right pane.</li><li><strong>Right — focus pane.</strong> Shows the selected idea&#39;s badges, serif title, italic hook, angle, tags, any discovery enrichment (views / likes / transcript), and an action footer (Edit · delete · Convert to script).</li></ul><h2 id="creating-ideas" tabindex="-1">Creating ideas <a class="header-anchor" href="#creating-ideas" aria-label="Permalink to &quot;Creating ideas&quot;">​</a></h2><h3 id="manual" tabindex="-1">Manual <a class="header-anchor" href="#manual" aria-label="Permalink to &quot;Manual&quot;">​</a></h3><p>Click <strong>Manual</strong> in the header. A pair of fields appears — title and hook — plus an <strong>Add</strong> button. Manual ideas track with <code>source: manual</code> and show a small <code>✎ Manual</code> chip.</p><h3 id="ai-generate" tabindex="-1">AI Generate <a class="header-anchor" href="#ai-generate" aria-label="Permalink to &quot;AI Generate&quot;">​</a></h3>',7)),i(o,{name:"ideas-generate",alt:"AI generate with inline context hint"}),e[3]||(e[3]=r('<p>The <strong>Generate 5 more</strong> button is always visible. Above the list sits an inline <strong>Context hint</strong> input — anything you type there (e.g. &quot;trending topic: kelp forests&quot;) is fed to the generator. The current model is shown next to the input; change it via the model picker. Click generate and five new ideas stream into the list, tagged with the model that produced them.</p><h3 id="from-discover" tabindex="-1">From Discover <a class="header-anchor" href="#from-discover" aria-label="Permalink to &quot;From Discover&quot;">​</a></h3><p>When researching YouTube videos in the <a href="/guide/discover.html">Discover</a> panel, click <strong>Inspire</strong> on any video. The idea lands here with <code>source: discover</code> and the video&#39;s metadata (views, duration, description, transcript if available) carried as enrichment — visible in the focus pane.</p><h2 id="working-the-list" tabindex="-1">Working the list <a class="header-anchor" href="#working-the-list" aria-label="Permalink to &quot;Working the list&quot;">​</a></h2><ul><li><strong>Search</strong> — type in the box above the list (<code>⌘F</code> focuses it in Chrome). Matches title, hook, angle, and tags.</li><li><strong>Sort</strong> — newest / oldest / title A–Z / source — switchable from the left rail&#39;s Sort dropdown.</li><li><strong>Type toggle</strong> — Short ↔ Long controls both filtering and what&#39;s used when you generate.</li><li><strong>Multi-select</strong> — checkboxes on each row. When anything is selected the toolbar shows <strong>Delete (n)</strong> and <strong>Cancel</strong>.</li></ul><h2 id="editing-an-idea" tabindex="-1">Editing an idea <a class="header-anchor" href="#editing-an-idea" aria-label="Permalink to &quot;Editing an idea&quot;">​</a></h2><p>Click a row to focus it, then <strong>Edit</strong> in the right pane. Title / hook / angle are inline form fields; save commits immediately.</p><h2 id="convert-to-script" tabindex="-1">Convert to script <a class="header-anchor" href="#convert-to-script" aria-label="Permalink to &quot;Convert to script&quot;">​</a></h2><p>From the focus pane, click <strong>Convert to script</strong>. A new script <strong>and</strong> a matching episode are created together (research is auto-approved so the episode lands directly in the board&#39;s <strong>Script</strong> column). The script carries the idea&#39;s title, hook, angle, and any enrichment data (e.g. Discover transcripts become reference material). The original idea is marked <code>convertedToScript</code> and disappears from Ideas — from here on, the board is where it lives.</p><div class="info custom-block"><p class="custom-block-title">Source tracking</p><p>Every idea records its <code>source</code> (<code>manual</code> / <code>ai</code> / <code>discover</code>). AI-sourced ideas also record the <code>generatedByModel</code> for reproducibility. The source chip in the list (<code>✦ AI · claude sonnet</code> / <code>⊕ Discover · 2.4M views</code>) makes provenance visible at a glance.</p></div>',10))])}const k=n(c,[["render",h]]);export{b as __pageData,k as default};
